223.             string nextRequestUri,
224.             string headerSource,
225.             string? lastKnownLocation,
226.             string finalStateVia,
227.             string? operationId = null)
228.         {
229.             // TODO: Once we remove NextLinkOperationImplementation from internal shared and make it internal to Azure.Core only in https://github.com/Azure/azure-sdk-for-net/issues/43260
230.             // We can access the internal members from RehydrationToken directly
231.             var json = $$"""
232.             {"version":"{{RehydrationTokenVersion}}","id":{{ConstructStringValue(operationId)}},"requestMethod":"{{requestMethod}}","initialUri":"{{startRequestUri.AbsoluteUri}}","nextRequestUri":"{{nextRequestUri}}","headerSource":"{{headerSource}}","finalStateVia":"{{finalStateVia}}","lastKnownLocation":{{ConstructStringValue(lastKnownLocation)}}}
233.             """;
234.             var data = new BinaryData(json);
235.             return ModelReaderWriter.Read<RehydrationToken>(data, ModelReaderWriterOptions.Json, AzureCoreContext.Default);
236.         }
